+namespace fmha {
+
+////////////////////////////////////////////////////////////////////////////////////////////////////
+
+template <int BYTES_PER_LDG>
+struct Fragment_ldg {};
+
+////////////////////////////////////////////////////////////////////////////////////////////////////
+
+template <>
+struct Fragment_ldg<1> {
+  template <typename Fragment>
+  static inline __device__ void ldg(Fragment& f, int ii, void const* ptr) {
+    uint8_t tmp;
+    fmha::ldg(tmp, ptr);
+    f.u8(ii) = tmp;
+  }
+};
+
+////////////////////////////////////////////////////////////////////////////////////////////////////
+
+template <>
+struct Fragment_ldg<2> {
+  template <typename Fragment>
+  static inline __device__ void ldg(Fragment& f, int ii, void const* ptr) {
+    uint16_t tmp;
+    fmha::ldg(tmp, ptr);
+    f.u16(ii) = tmp;
+  }
+};
+
+////////////////////////////////////////////////////////////////////////////////////////////////////
+
+template <>
+struct Fragment_ldg<4> {
+  template <typename Fragment>
+  static inline __device__ void ldg(Fragment& f, int ii, void const* ptr) {
+    uint32_t tmp;
+    fmha::ldg(tmp, ptr);
+    f.reg(ii) = tmp;
+  }
+};
+
+////////////////////////////////////////////////////////////////////////////////////////////////////
+
+template <>
+struct Fragment_ldg<8> {
+  template <typename Fragment>
+  static inline __device__ void ldg(Fragment& f, int ii, void const* ptr) {
+    uint2 tmp;
+    fmha::ldg(tmp, ptr);
+    f.reg(2 * ii + 0) = tmp.x;
+    f.reg(2 * ii + 1) = tmp.y;
+  }
+};
+
+////////////////////////////////////////////////////////////////////////////////////////////////////
+
+template <>
+struct Fragment_ldg<16> {
+  template <typename Fragment>
+  static inline __device__ void ldg(Fragment& f, int ii, void const* ptr) {
+    uint4 tmp;
+    fmha::ldg(tmp, ptr);
+    f.reg(4 * ii + 0) = tmp.x;
+    f.reg(4 * ii + 1) = tmp.y;
+    f.reg(4 * ii + 2) = tmp.z;
+    f.reg(4 * ii + 3) = tmp.w;
+  }
+};
+
+////////////////////////////////////////////////////////////////////////////////////////////////////
+
+template <int BYTES_PER_LDS>
+struct Fragment_lds {};
+
+////////////////////////////////////////////////////////////////////////////////////////////////////
+
+template <>
+struct Fragment_lds<2> {
+  template <typename Fragment>
+  static inline __device__ void lds(Fragment& f, int ii, uint32_t ptr) {
+    uint16_t tmp;
+    fmha::lds(tmp, ptr);
+    f.u16(ii) = tmp;
+  }
+};
+
+////////////////////////////////////////////////////////////////////////////////////////////////////
+
+template <>
+struct Fragment_lds<4> {
+  template <typename Fragment>
+  static inline __device__ void lds(Fragment& f, int ii, uint32_t ptr) {
+    uint32_t tmp;
+    fmha::lds(tmp, ptr);
+    f.reg(ii) = tmp;
+  }
+};
+
+////////////////////////////////////////////////////////////////////////////////////////////////////
+
+template <>
+struct Fragment_lds<8> {
+  template <typename Fragment>
+  static inline __device__ void lds(Fragment& f, int ii, uint32_t ptr) {
+    uint2 tmp;
+    fmha::lds(tmp, ptr);
+    f.reg(2 * ii + 0) = tmp.x;
+    f.reg(2 * ii + 1) = tmp.y;
+  }
+};
+
+////////////////////////////////////////////////////////////////////////////////////////////////////
+
+template <>
+struct Fragment_lds<16> {
+  template <typename Fragment>
+  static inline __device__ void lds(Fragment& f, int ii, uint32_t ptr) {
+    uint4 tmp;
+    fmha::lds(tmp, ptr);
+    f.reg(4 * ii + 0) = tmp.x;
+    f.reg(4 * ii + 1) = tmp.y;
