+//     static inline __device__ void lds(Fragment &f, int ii, uint32_t ptr) {
+//         uint4 tmp;
+//         fmha::lds(tmp, ptr);
+//         f.reg(8*ii+0) = tmp.x;
+//         f.reg(8*ii+1) = tmp.y;
