+        : "r"(a.reg(0)), "r"(a.reg(1)), "r"(b.reg(0)), "r"(b.reg(1)));
+    asm volatile(
+        "mma.sync.aligned.m8n8k4.row.col.f16.f16.f16.f16 \n"
+        "    {%0, %1, %2, %3}, \n"
+        "    {%4, %5}, \n"
