+          : "+r"(reg(i * 2 + 0)), "+r"(reg(i * 2 + 1))
+          : "r"(a.reg(0)), "r"(a.reg(1)), "r"(a.reg(2)), "r"(a.reg(3)), "r"(b.reg(i * 2)),
