+#ifdef HALF_ACCUMULATION_FOR_FLASH_ATTENTION  // Half accumulation
+#pragma unroll
+    for (int mi = 0; mi < MMAS_M; ++mi) {
+      // Precompute the scaling factors.
+      uint32_t beta;
+      // The divisor.
+      float b = (sum[mi] == 0.f || sum[mi] != sum[mi]) ? 1.f : 1.f / sum[mi];
