+      float a = prev_sum_[mi] * __expf(prev_max_[mi] - curr_max_[mi]);
+      // The diviser.
+      float b =
+          (curr_sum_[mi] == 0.f || curr_sum_[mi] != curr_sum_[mi]) ? 1.f : 1.f / curr_sum_[mi];
+      // Convert back to FP16.
+      alpha = fmha::float2_to_half2(a, a);
+      beta = fmha::float2_to_half2(b, b);
