+    // The last CTA stores INT8 values to the final location.
+    if (blockIdx.x == CTAS_PER_HEAD - 1) {
+      this->store(tmp, mi);
+
+      // Other CTAs store INT32 values to the scratch space.
+    } else if (ALL_THREADS_ACTIVE || is_active_) {
