+static inline __device__ uint16_t pack_char2(uint32_t a, uint32_t b) {
+  uint32_t dst;
+  asm volatile("prmt.b32 %0, %1, %2, 0x0040;\n" : "=r"(dst) : "r"(a), "r"(b));
+  return reinterpret_cast<uint16_t&>(dst);
+}
