+#if (defined(__CUDA_ARCH__) && (__CUDA_ARCH__ >= 900))
+  uint16_t storage;
+  asm volatile("{cvt.rn.satfinite.e4m3x2.f32 %0, %2, %1;}\n" : "=h"(storage) : "f"(x), "f"(y));
+  return storage;
+#else
+  assert(false);
+  return 0;
+#endif
+}
