+    // A thread holds packet of 2 elements. In 2x2 tile per MMA.
+    // Need to figure out if we need this for hopper.
+    int64_t const step_m = 8 * (this->params_stride_in_bytes_);
+    int64_t const step_n = 8 * BYTES_PER_ELEMENT;
