+#pragma unroll
+      for (int kbi = 0; kbi < NUM_KGROUPS - 1; kbi++) {
+#pragma unroll
+        for (int ki = 0; ki < MMAS_K_PER_GROUP; ki++) {
+          fill_frag_a(frag_a[kbi * MMAS_K_PER_GROUP + ki][0]);
